import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.ruleset.standard.rules.TrailingCommaOnDeclarationSiteRule.Companion.TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class TrailingCommaOnDeclarationSiteEmptyEnumTest {
    private val trailingCommaOnDeclarationSiteRuleAssertThat =
        KtLintAssertThat.assertThatRule(
            provider = { TrailingCommaOnDeclarationSiteRule() },
            additionalRuleProviders = setOf(
                // WrappingRule must be loaded in order to run TrailingCommaOnDeclarationSiteRule
                RuleProvider { WrappingRule() },
                // Apply the IndentationRule always as additional rule, so that the formattedCode in the unit test looks
                // correct.
                RuleProvider { IndentationRule() },
            ),
        )

    @Test
    fun `Given an empty enum class then no error should be raised`() {
        val code =
            """
            enum class EmptyEnum
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }

    @Test
    fun `Given an empty enum class with braces then no error should be raised`() {
        val code =
            """
            enum class EmptyEnum {}
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }

    @Test
    fun `Given an empty enum class with multiline braces then no error should be raised`() {
        val code =
            """
            enum class EmptyEnum {
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }

    @Test
    fun `Given an empty enum class with semicolon then no error should be raised`() {
        val code =
            """
            enum class EmptyEnum {
                ;
                fun someMethod() = "test"
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }

    @Test
    fun `Given an empty enum class with trailing comma disabled then no error should be raised`() {
        val code =
            """
            enum class EmptyEnum {
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to false)
            .hasNoLintViolations()
    }
}
"}

